    K_THREAD_DEFINE(admin_task_id, 1024, admin_task, NULL, NULL, NULL, 1, 1);
    K_THREAD_DEFINE(user_task_id, 1024, user_task, NULL, NULL, NULL, 1, 1);
    
    while (1) {
        k_msleep(1000);
    }
